sys_ws_operation.operation_script:
(function process(/*RESTAPIRequest*/ request, /*RESTAPIResponse*/ response) {

	var requestBody = request.body;
	var metaDataString = requestBody;
	var objMetaData = JSON.parse(requestBody.dataString);

	var responseObj = _cloneTemplate(objMetaData);

	response.setBody(responseObj);

	response.setStatus(200);
	response.setContentType('application/json');


	function _cloneTemplate(metaData){
		var apiTaskerTemplate = new api_tasker_template();
		var cloneResponse;
		var validMetaData = apiTaskerTemplate.validateCloneMetaData("template_api.cloneTemplate", metaData);
		if(validMetaData.validCallData){
			cloneResponse = apiTaskerTemplate.cloneTemplate(validMetaData.template_id, 
															validMetaData.new_template_name, validMetaData.new_template_owner);
			metaData.success = cloneResponse.templateCloned==true;
			if(cloneResponse.templateCloned){
				metaData.new_topTask_id = cloneResponse.new_topTask_id;
			}
		}  // note, if invalid call data, success is set to false inside metadata check
		return metaData;

	}

})(request, response);
